const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json({ limit: '10mb' }));

const esClient = new Client({
  node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200',
  auth: {
    username: process.env.ES_USERNAME || 'elastic',
    password: process.env.ES_PASSWORD || 'changeme'
  }
});

function buildBaseQuery(searchParams) {
  const { query, fields, filters, fuzzy, boost } = searchParams;
  
  let baseQuery = { bool: { must: [], filter: [], should: [] } };

  if (query) {
    if (fields && fields.length > 0) {
      baseQuery.bool.must.push({
        multi_match: {
          query: query,
          fields: fields,
          fuzziness: fuzzy || 'AUTO',
          boost: boost || 1
        }
      });
    } else {
      baseQuery.bool.must.push({
        query_string: {
          query: query,
          fuzziness: fuzzy || 'AUTO'
        }
      });
    }
  }

  if (filters) {
    if (filters.term) {
      Object.entries(filters.term).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ term: { [field]: value } });
      });
    }
    
    if (filters.range) {
      Object.entries(filters.range).forEach(([field, rangeParams]) => {
        baseQuery.bool.filter.push({ range: { [field]: rangeParams } });
      });
    }
    
    if (filters.exists) {
      filters.exists.forEach(field => {
        baseQuery.bool.filter.push({ exists: { field } });
      });
    }
    
    if (filters.match) {
      Object.entries(filters.match).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ match: { [field]: value } });
      });
    }
  }

  if (baseQuery.bool.must.length === 0 && baseQuery.bool.filter.length === 0) {
    return { match_all: {} };
  }

  return baseQuery;
}

function buildScriptScoreQuery(baseQuery, scriptConfig) {
  const { source, params, lang } = scriptConfig;
  
  return {
    script_score: {
      query: baseQuery,
      script: {
        source: source,
        params: params || {},
        lang: lang || 'painless'
      },
      min_score: scriptConfig.min_score,
      boost: scriptConfig.boost
    }
  };
}

function buildAggregations(aggConfig) {
  if (!aggConfig) return undefined;
  
  const aggregations = {};
  
  if (aggConfig.terms) {
    aggConfig.terms.forEach(termAgg => {
      aggregations[termAgg.name] = {
        terms: {
          field: termAgg.field,
          size: termAgg.size || 10,
          order: termAgg.order || { _count: 'desc' }
        }
      };
    });
  }
  
  if (aggConfig.stats) {
    aggConfig.stats.forEach(statAgg => {
      aggregations[statAgg.name] = {
        stats: {
          field: statAgg.field
        }
      };
    });
  }
  
  if (aggConfig.histogram) {
    aggConfig.histogram.forEach(histAgg => {
      aggregations[histAgg.name] = {
        histogram: {
          field: histAgg.field,
          interval: histAgg.interval
        }
      };
    });
  }
  
  if (aggConfig.date_histogram) {
    aggConfig.date_histogram.forEach(dateHistAgg => {
      aggregations[dateHistAgg.name] = {
        date_histogram: {
          field: dateHistAgg.field,
          calendar_interval: dateHistAgg.interval || '1d'
        }
      };
    });
  }

  return Object.keys(aggregations).length > 0 ? aggregations : undefined;
}

function buildHighlight(highlightConfig) {
  if (!highlightConfig) return undefined;
  
  return {
    fields: highlightConfig.fields || {},
    pre_tags: highlightConfig.pre_tags || ['<em>'],
    post_tags: highlightConfig.post_tags || ['</em>'],
    fragment_size: highlightConfig.fragment_size || 150,
    number_of_fragments: highlightConfig.number_of_fragments || 3
  };
}

app.post('/search', async (req, res) => {
  try {
    const {
      index,
      searchParams,
      scriptScore,
      aggregations,
      highlight,
      sort,
      from,
      size,
      source
    } = req.body;

    if (!index) {
      return res.status(400).json({ error: 'Index name is required' });
    }

    const baseQuery = buildBaseQuery(searchParams || {});
    
    let finalQuery = baseQuery;
    if (scriptScore && scriptScore.source) {
      finalQuery = buildScriptScoreQuery(baseQuery, scriptScore);
    }

    const searchBody = {
      query: finalQuery,
      from: from || 0,
      size: size || 10
    };

    if (aggregations) {
      searchBody.aggs = buildAggregations(aggregations);
    }

    if (highlight) {
      searchBody.highlight = buildHighlight(highlight);
    }

    if (sort) {
      searchBody.sort = sort;
    }

    if (source !== undefined) {
      searchBody._source = source;
    }

    const result = await esClient.search({
      index: index,
      body: searchBody
    });

    res.json({
      total: result.hits.total,
      hits: result.hits.hits,
      aggregations: result.aggregations,
      took: result.took
    });

  } catch (error) {
    console.error('Search error:', error);
    res.status(500).json({ 
      error: 'Search failed', 
      message: error.message,
      details: error.meta?.body?.error
    });
  }
});

